import { useState, useEffect } from "react";
import { useNavigate, useParams } from "react-router-dom";
import "./EmployeeForm.css";

function AddEmployee() {

  const navigate = useNavigate();
  const { id } = useParams();
  const isEditMode = Boolean(id);

  const [activeTab,setActiveTab] = useState("personal");

  const [employee,setEmployee] = useState({
    firstName:"",
    lastName:"",
    empId:"",
    gender:"",
    dob:"",
    maritalStatus:"",
    email:"",
    aadhar:"",
    pan:"",
    designation:"",
    department:"",
    salary:"",
    role:"",
    skills:[],
    tempSkill:"",
    customSkill:"",
    bankName:"",
    accountNumber:"",
    ifsc:"",
    qualification:"",
    university:"",
    passingYear:"",
    employeeFiles:[],
    certificates:[]
  });

  const skillOptions=[
    "C","C++","Java","Advanced Java","Python",
    "NodeJS","React","Angular","MongoDB"
  ];

  const [designations,setDesignations]=useState([]);

  /* ================= LOAD DESIGNATIONS ================= */
  useEffect(()=>{
    const saved=JSON.parse(localStorage.getItem("designations"))||[];
    setDesignations(saved);
  },[]);


  /* =====================================================
     ✅ LOAD EMPLOYEE FROM BACKEND (EDIT MODE)
  ===================================================== */
  useEffect(() => {

    if (!isEditMode) return;

    const loadEmployee = async () => {

      try {

        const token = localStorage.getItem("token");

        const res = await fetch(
          `http://localhost:8080/api/profile/${id}`,
          {
            headers: {
              Authorization: `Bearer ${token}`
            }
          }
        );

        if(!res.ok) throw new Error("Load failed");

        const data = await res.json();

        setEmployee(prev => ({
          ...prev,
          ...data,
          skills: data.skills || [],
          employeeFiles: data.employeeFiles || [],
          certificates: data.certificates || []
        }));

      } catch(err) {
        console.error("Edit Load Error:", err);
      }
    };

    loadEmployee();

  }, [id, isEditMode]);


  /* =====================================================
     INPUT HANDLING
  ===================================================== */
  const handleChange=(e)=>{
    const {name,value}=e.target;

    if(name==="pan"){
      setEmployee({...employee,pan:value.toUpperCase()});
      return;
    }

    setEmployee({...employee,[name]:value});
  };


  /* ================= SKILLS ================= */
  const addSkill=()=>{
    let newSkill="";

    if(employee.tempSkill==="Other"){
      if(!employee.customSkill.trim()) return;
      newSkill=employee.customSkill.trim();
    }else{
      if(!employee.tempSkill) return;
      newSkill=employee.tempSkill;
    }

    if(!employee.skills.includes(newSkill)){
      setEmployee(prev=>({
        ...prev,
        skills:[...prev.skills,newSkill],
        tempSkill:"",
        customSkill:""
      }));
    }
  };

  const removeSkill=(skill)=>{
    setEmployee(prev=>({
      ...prev,
      skills:prev.skills.filter(s=>s!==skill)
    }));
  };


  /* =====================================================
     ✅ SAVE TO BACKEND
  ===================================================== */
  const handleSubmit = async (e) => {

    e.preventDefault();

    try {

      const token = localStorage.getItem("token");

      const url = isEditMode
        ? `http://localhost:8080/api/profile/${id}`
        : `http://localhost:8080/api/profile`;

      const method = isEditMode ? "PUT" : "POST";

      const res = await fetch(url, {
        method,
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${token}`
        },
        body: JSON.stringify(employee)
      });

      if(!res.ok){
        alert("Save Failed");
        return;
      }

      alert("Saved Successfully");

      navigate("/admin-dashboard/employee-details");

    } catch(err) {
      console.error(err);
      alert("Server Error");
    }
  };


  /* ================= UI ================= */

  const Field=(label,element)=>(
    <div className="form-field">
      <label>{label}</label>
      {element}
    </div>
  );

  return (
    <div className="add-employee-page">

      <h2>{isEditMode?"Edit Employee":"Add Employee"}</h2>

      <div className="tabs">
        {["personal","employment","bank","education"].map(t=>(
          <button key={t}
            className={`tab ${activeTab===t?"active":""}`}
            onClick={()=>setActiveTab(t)}>
            {t.toUpperCase()}
          </button>
        ))}
      </div>

      <form className="employee-form" onSubmit={handleSubmit}>

        {/* ---- KEEP YOUR ENTIRE FORM UI BELOW EXACTLY SAME ---- */}
        {/* (I intentionally did not change layout/fields to avoid breaking UI) */}

        {/* PERSONAL */}
        {activeTab==="personal" && (
          <>
            <h3>Personal Details</h3>
            <div className="employee-grid">

              {Field("First Name",
                <input name="firstName" value={employee.firstName} onChange={handleChange}/>
              )}

              {Field("Last Name",
                <input name="lastName" value={employee.lastName} onChange={handleChange}/>
              )}

              {Field("Employee ID",
                <input name="empId" value={employee.empId} onChange={handleChange}/>
              )}

              {Field("Gender",
                <select name="gender" value={employee.gender} onChange={handleChange}>
                  <option value="">Select</option>
                  <option>Male</option>
                  <option>Female</option>
                </select>
              )}

              {Field("Date of Birth",
                <input type="date" name="dob" value={employee.dob} onChange={handleChange}/>
              )}

              {Field("Marital Status",
                <select name="maritalStatus" value={employee.maritalStatus} onChange={handleChange}>
                  <option value="">Select</option>
                  <option>Single</option>
                  <option>Married</option>
                </select>
              )}

              {Field("Email",
                <input type="email" name="email" value={employee.email} onChange={handleChange}/>
              )}

              {Field("Aadhar Number",
                <input name="aadhar" maxLength="12" value={employee.aadhar} onChange={handleChange}/>
              )}

              {Field("PAN Number",
                <input name="pan" maxLength="10" value={employee.pan} onChange={handleChange}/>
              )}

            </div>
          </>
        )}

        {/* ===== KEEP OTHER TABS SAME AS YOUR ORIGINAL ===== */}

        <button className="save-btn" type="submit">
          {isEditMode?"Update Employee":"Save Employee"}
        </button>

      </form>
    </div>
  );
}

export default AddEmployee;
